// Parse the AI agent output and chat input
const chatInput = $('Chat - University Request').first().json.chatInput;
const aiResponse = $input.first().json.output;

// Extract the university name from the chat input
const universityName = chatInput;

// Try to parse the response as JSON, or use as-is
let researchData;
try {
  researchData = typeof aiResponse === 'string' ? JSON.parse(aiResponse) : aiResponse;
} catch (error) {
  // If not JSON, structure it ourselves
  researchData = {
    universityInfo: aiResponse,
    universityName: universityName
  };
}

// Ensure we have the university name
researchData.universityName = universityName;

// Get current date
const today = new Date();
researchData.researchDate = today.toISOString().split('T')[0];

// Format for Google Docs
const docContent = `
# ${universityName} - Business Program Application Guide
## For Canadian Grade 12 Students
### Research Date: ${researchData.researchDate}

---

## 1. UNIVERSITY OVERVIEW
${researchData['1. UNIVERSITY OVERVIEW'] || researchData.universityOverview || 'Information to be researched'}

## 2. ADMISSION REQUIREMENTS
${researchData['2. ADMISSION REQUIREMENTS'] || researchData.admissionRequirements || 'Information to be researched'}

## 3. IMPORTANT DATES & DEADLINES
${researchData['3. IMPORTANT DATES & DEADLINES'] || researchData.importantDates || 'Information to be researched'}

## 4. APPLICATION PROCESS
${researchData['4. APPLICATION PROCESS'] || researchData.applicationProcess || 'Information to be researched'}

## 5. PROGRAM DETAILS
${researchData['5. PROGRAM DETAILS'] || researchData.programDetails || 'Information to be researched'}

## 6. FINANCIAL INFORMATION
${researchData['6. FINANCIAL INFORMATION'] || researchData.financialInfo || 'Information to be researched'}

## 7. STRATEGIES TO INCREASE ACCEPTANCE
${researchData['7. STRATEGIES TO INCREASE ACCEPTANCE'] || researchData.strategies || 'Information to be researched'}

## 8. RESOURCES & CONTACTS
${researchData['8. RESOURCES & CONTACTS'] || researchData.resources || 'Information to be researched'}

---

## EXTERNAL SCHOLARSHIP OPPORTUNITIES

### Major Canadian Scholarships:
- **Loran Scholars Foundation** - $100,000 over 4 years
  - Deadline: October (Grade 12)
  - Requires nomination from school

- **TD Scholarships for Community Leadership** - $70,000
  - Deadline: November
  - Focus on community involvement

- **Schulich Leader Scholarships** - $100,000 (STEM) or $80,000 (Business)
  - Deadline: January
  - Requires school nomination

- **Terry Fox Humanitarian Award** - $28,000
  - Deadline: February
  - Focus on humanitarian service

### Provincial Scholarships:
- Check your provincial student aid website
- Ontario: OSAP and Ontario Scholar designation
- Other provinces have similar programs

---

## ACTION PLAN

1. **Immediate Actions (This Week)**
   - Review all requirements carefully
   - Check your current grades against minimums
   - Start gathering documents

2. **Short-term (Next 2-4 Weeks)**
   - Request transcripts
   - Ask for reference letters
   - Begin essay drafts

3. **Application Period**
   - Submit 2 weeks before deadline
   - Double-check all requirements
   - Apply for scholarships simultaneously

4. **Follow-up**
   - Confirm receipt of application
   - Send thank you notes to references
   - Prepare for potential interviews

---

*Note: This guide was compiled for educational purposes. Always verify information directly with the university's official admissions office.*
`;

// Extract deadlines for spreadsheet
const deadlines = [];

// Parse deadlines from the research (this is a simplified version)
const deadlineSection = researchData['3. IMPORTANT DATES & DEADLINES'] || researchData.importantDates || '';

// Add standard deadline entries
const standardDeadlines = [
  { descriptor: 'Early Admission Application', hardDeadline: '2025-11-01' },
  { descriptor: 'Regular Application Deadline', hardDeadline: '2026-01-15' },
  { descriptor: 'Document Submission', hardDeadline: '2026-02-01' },
  { descriptor: 'Entrance Scholarship Application', hardDeadline: '2026-02-15' },
  { descriptor: 'Loran Scholars Nomination', hardDeadline: '2025-10-15' },
  { descriptor: 'TD Community Leadership Scholarship', hardDeadline: '2025-11-15' },
  { descriptor: 'Schulich Leader Nomination', hardDeadline: '2026-01-15' },
  { descriptor: 'Terry Fox Humanitarian Award', hardDeadline: '2026-02-01' },
  { descriptor: 'Acceptance Decision Deadline', hardDeadline: '2026-06-01' },
  { descriptor: 'Residence Application', hardDeadline: '2026-06-15' }
];

// Calculate personal deadlines (2 weeks before)
standardDeadlines.forEach(item => {
  const hardDate = new Date(item.hardDeadline);
  const personalDate = new Date(hardDate);
  personalDate.setDate(personalDate.getDate() - 14);

  deadlines.push({
    Descriptor: `${universityName} - ${item.descriptor}`,
    'Personal Deadline': personalDate.toISOString().split('T')[0],
    'Hard Deadline': item.hardDeadline
  });
});

return [
  {
    json: {
      universityName: universityName,
      docContent: docContent,
      deadlines: deadlines,
      researchData: researchData
    }
  }
];

const universityName = $('Process Research Data').first().json.universityName;
const docUrl = $('Create Google Doc').first().json.documentUrl || 'Document created successfully';
const spreadsheetUrl = $('Create Deadline Spreadsheet').first().json.spreadsheetUrl || 'Spreadsheet created successfully';
const deadlineCount = $('Process Research Data').first().json.deadlines.length;

// Format response message for chat
const responseMessage = `
✅ **Research completed for ${universityName}!**

📄 **Google Doc Created:**
I've created a comprehensive research guide with all admission information.
[View Document](${docUrl})

📊 **Google Sheet Created:**
I've created a deadline tracker with ${deadlineCount} important dates.
Note: Personal deadlines are set 2 weeks before official deadlines.
[View Spreadsheet](${spreadsheetUrl})
